import React, { useState, useEffect } from 'react';
import { Routes, Route } from 'react-router-dom';
import Sidebar from '../Layout/Sidebar';
import Navbar from '../Layout/Navbar';
import api from '../../services/api';
import { useAuth } from '../../context/AuthContext';
import { Users, FileText, Calendar, TrendingUp } from 'lucide-react';
import NoticeUpload from './NoticeUpload';
import AttendanceManagement from './AttendanceManagement';
import ScoreManagement from './ScoreManagement';

const TeacherDashboard = () => {
  const { user } = useAuth();
  const [stats, setStats] = useState({
    totalStudents: 0,
    recentUploads: 0,
    activeNotices: 0
  });

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const response = await api.get(`/teachers/${user.teacherId}/dashboard`);
      if (response.data.success) {
        setStats(response.data.data);
      }
    } catch (error) {
      console.error('Error fetching stats:', error);
    }
  };

  const DashboardHome = () => (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="card">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-gray-500 text-sm">Total Students</p>
              <p className="text-2xl font-bold text-gray-800 mt-1">{stats.totalStudents}</p>
            </div>
            <Users className="w-12 h-12 text-blue-600 opacity-50" />
          </div>
        </div>
        <div className="card">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-gray-500 text-sm">Recent Uploads</p>
              <p className="text-2xl font-bold text-gray-800 mt-1">{stats.recentUploads}</p>
            </div>
            <FileText className="w-12 h-12 text-green-600 opacity-50" />
          </div>
        </div>
        <div className="card">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-gray-500 text-sm">Active Notices</p>
              <p className="text-2xl font-bold text-gray-800 mt-1">{stats.activeNotices}</p>
            </div>
            <Calendar className="w-12 h-12 text-purple-600 opacity-50" />
          </div>
        </div>
      </div>

      <div className="card">
        <h2 className="text-lg font-semibold text-gray-800 mb-4">Quick Actions</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <button className="p-4 bg-blue-50 rounded-lg text-left hover:bg-blue-100 transition-colors">
            <FileText className="w-6 h-6 text-blue-600 mb-2" />
            <p className="font-medium">Post New Notice</p>
            <p className="text-sm text-gray-600">Share announcements with students</p>
          </button>
          <button className="p-4 bg-green-50 rounded-lg text-left hover:bg-green-100 transition-colors">
            <Calendar className="w-6 h-6 text-green-600 mb-2" />
            <p className="font-medium">Update Attendance</p>
            <p className="text-sm text-gray-600">Manage student attendance records</p>
          </button>
          <button className="p-4 bg-purple-50 rounded-lg text-left hover:bg-purple-100 transition-colors">
            <TrendingUp className="w-6 h-6 text-purple-600 mb-2" />
            <p className="font-medium">Upload Scores</p>
            <p className="text-sm text-gray-600">Enter exam results</p>
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <div className="flex h-screen bg-gray-50">
      <Sidebar role="teacher" />
      <div className="flex-1 ml-64">
        <Navbar />
        <main className="p-6">
          <Routes>
            <Route path="/" element={<DashboardHome />} />
            <Route path="/notices" element={<NoticeUpload />} />
            <Route path="/attendance" element={<AttendanceManagement />} />
            <Route path="/scores" element={<ScoreManagement />} />
          </Routes>
        </main>
      </div>
    </div>
  );
};

export default TeacherDashboard;
